I'll help you add rate limiting middleware to your Express app. Here's how to implement it:

## Step 1: Install the package
First, install the `express-rate-limit` package:

```bash
npm install express-rate-limit
```

## Step 2: Add rate limiting to your Express app

Here's how to add it to your `src/server.js`:

```javascript
const express = require('express');
const rateLimit = require('express-rate-limit');

const app = express();

// Basic rate limiting configuration
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again after 15 minutes',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});

// Apply rate limiting to all requests
app.use(limiter);

// Or apply to specific routes only
app.use('/api/', limiter); // Only apply to API routes

// Your existing routes...
app.get('/', (req, res) => {
  res.send('Hello World!');
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

## Step 3: Advanced Configuration Options

Here are some more advanced configurations you might want to consider:

```javascript
// Different rate limits for different routes
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: 'Too many API requests from this IP',
});

const authLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 5, // Only 5 login attempts per hour
  message: 'Too many login attempts, please try again after an hour',
});

const publicLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 30, // 30 requests per minute for public endpoints
  message: 'Too many requests, please slow down',
});

// Apply different limiters to different routes
app.use('/api/', apiLimiter);
app.use('/auth/login', authLimiter);
app.use('/public/', publicLimiter);

// Skip rate limiting for certain IPs or conditions
const skipLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  skip: (req, res) => {
    // Skip rate limiting for localhost or trusted IPs
    return req.ip === '127.0.0.1' || req.ip === '::1';
  },
  keyGenerator: (req, res) => {
    // Custom key generator (e.g., use user ID if authenticated)
    return req.user ? req.user.id : req.ip;
  }
});
```

## Step 4: Environment-based Configuration

For better flexibility, you can configure rate limits based on environment:

```javascript
const isProduction = process.env.NODE_ENV === 'production';

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: isProduction ? 100 : 1000, // Higher limit in development
  message: {
    status: 429,
    error: 'Too many requests',
    message: 'Please try again later'
  },
  handler: (req, res, next, options) => {
    // Custom handler for when limit is exceeded
    res.status(options.statusCode).json(options.message);
  },
  skipFailedRequests: false, // Count failed requests (like 404s)
  skipSuccessfulRequests: false, // Count successful requests
});
```

## Step 5: With Redis Store (for distributed systems)

If you're running multiple instances of your app, use Redis to share rate limit data:

```bash
npm install rate-limit-redis
```

```javascript
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');

const redisClient = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
});

const limiter = rateLimit({
  store: new RedisStore({
    sendCommand: (...args) => redisClient.call(...args),
  }),
  windowMs: 15 * 60 * 1000,
  max: 100,
});
```

## Complete Example

Here's a complete example with multiple rate limiters:

```javascript
const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet'); // Also consider adding security headers

const app = express();

// Security middleware
app.use(helmet());

// Global rate limiter (less strict)
const globalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  message: 'Too many requests from this IP',
  standardHeaders: true,
  legacyHeaders: false,
});

// Apply global limiter to all routes
app.use(globalLimiter);

// Stricter limiter for API routes
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 50,
  message: 'Too many API requests',
  skip: (req) => req.path.includes('/public/'), // Skip for public endpoints
});

// Apply to API routes
app.use('/api/', apiLimiter);

// Very strict limiter for authentication
const authLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 5,
  message: 'Too many login attempts',
});

app.use('/auth/', authLimiter);

// Your routes
app.get('/', (req, res) => {
  res.send('Hello World!');
});

app.get('/api/data', (req, res) => {
  res.json({ data: 'Protected API data' });
});

app.post('/auth/login', (req, res) => {
  // Login logic
  res.json({ token: 'jwt-token' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running with rate limiting on port ${PORT}`);
});
```

## Key Points:

1. **WindowMs**: The time window for counting requests (in milliseconds)
2. **Max**: Maximum number of requests allowed per window per key
3. **Key Generator**: By default uses IP address, but you can customize it
4. **Headers**: The middleware adds RateLimit headers to responses
5. **Status Code**: Returns 429 (Too Many Requests) when limit is exceeded

Choose the configuration that best fits your application's needs. For most applications, starting with a basic configuration (15 minutes, 100 requests) is a good starting point.

