        error: 'Refresh token is no longer valid.' 
      });
    }

    req.user = user;
    req.accessToken = accessToken;
    req.refreshToken = refreshToken;
    req.tokenData = {
      access: accessTokenData,
      refresh: refreshTokenData
    };
    next();
  } catch (error) {
    console.error('Token validation error:', error);

    if (error.name === 'JsonWebTokenError' || error.name === 'TokenExpiredError') {
      return res.status(401).json({ 
        error: 'Invalid or expired tokens.' 
      });
    }

    res.status(500).json({ 
      error: 'Internal server error during token validation.' 
    });
  }
};

// Helper function to generate tokens
const generateTokens = (userId) => {
  const accessToken = jwt.sign(
    {
      userId,
      type: TOKEN_TYPES.ACCESS
    },
    process.env.JWT_ACCESS_SECRET,
    { expiresIn: process.env.JWT_ACCESS_EXPIRY || '15m' }
  );

  const refreshToken = jwt.sign(
    {
      userId,
      type: TOKEN_TYPES.REFRESH,
      version: Date.now() // Using timestamp as version for simplicity
    },
    process.env.JWT_REFRESH_SECRET,
    { expiresIn: process.env.JWT_REFRESH_EXPIRY || '7d' }
  );

  return { accessToken, refreshToken };
};

// Helper to set tokens in response cookies (optional)
const setTokenCookies = (res, accessToken, refreshToken) => {
  const isProduction = process.env.NODE_ENV === 'production';

  // Set access token cookie
  res.cookie('accessToken', accessToken, {
    httpOnly: true,
    secure: isProduction,
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000 // 15 minutes
  });

  // Set refresh token cookie
  res.cookie('refreshToken', refreshToken, {
    httpOnly: true,
    secure: isProduction,
    sameSite: 'strict',
    maxAge: 7 * 24 * 60 * 60 * 1000 // 7 days
  });
};

// Helper to clear token cookies
const clearTokenCookies = (res) => {
  res.clearCookie('accessToken');
  res.clearCookie('refreshToken');
};

module.exports = {
  authenticate,
  authenticateRefreshToken,
  validateTokensForRefresh,
  generateTokens,
  setTokenCookies,
  clearTokenCookies,
  TOKEN_TYPES
};
