```javascript:src/routes/auth.js
const express = require('express');
const router = express.Router();
const { 
  authenticate, 
  authenticateRefreshToken,
  validateTokensForRefresh,
  generateTokens,
  setTokenCookies,
  clearTokenCookies 
} = require('../middleware/auth');
const User = require('../models/User');

// Login route
router.post('/login', async (req, res) => {
  try {
    // ... authentication logic ...
    const user = await User.findOne({ email: req.body.email });

    // Generate tokens
    const tokens = generateTokens(user._id);

    // Update refresh token version in database
    user.refreshTokenVersion = Date.now().toString();
    await user.save();

    // Set cookies if using cookie-based auth
    setTokenCookies(res, tokens.accessToken, tokens.refreshToken);

    res.json({
      message: 'Login successful',
      tokens,
      user: { id: user._id, email: user.email }
    });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// Refresh token route
router.post('/refresh', validateTokensForRefresh, async (req, res) => {
  try {
    const user = req.user;

    // Generate new tokens
    const tokens = generateTokens(user._id);

    // Update refresh token version (invalidates old refresh token)
    user.refreshTokenVersion = Date.now().toString();
    await user.save();

    // Set new cookies
    setTokenCookies(res, tokens.accessToken, tokens.refreshToken);

    res.json({
      message: 'Tokens refreshed successfully',
      tokens
    });
  } catch (error) {
    res.status(500).json({ error: 'Failed to refresh tokens' });
  }
});

// Logout route
router.post('/logout', authenticate, async (req, res) => {
  try {
    const user = req.user;

    // Invalidate refresh token by changing version
    user.refreshTokenVersion = Date.now().toString();
    await user.save();

    // Clear cookies
    clearTokenCookies(res);

    res.json({ message: 'Logged out successfully' });
  } catch (error) {
    res.status(500).json({ error: 'Logout failed' });
  }
});

// Protected route example
router.get('/profile', authenticate, (req, res) => {
  res.json({ user: req.user });
});

module.exports = router;
