I'll help you refactor the database layer to use connection pooling. Here are the changes for each file:

## 1. **src/db/connection.js** - Create connection pool

```javascript
const mysql = require('mysql2/promise');
require('dotenv').config();

// Create connection pool
const pool = mysql.createPool({
  host: process.env.DB_HOST || 'localhost',
  user: process.env.DB_USER || 'root',
  password: process.env.DB_PASSWORD || '',
  database: process.env.DB_NAME || 'your_database',
  port: process.env.DB_PORT || 3306,
  waitForConnections: true,
  connectionLimit: process.env.DB_POOL_LIMIT || 10,
  queueLimit: 0,
  enableKeepAlive: true,
  keepAliveInitialDelay: 0
});

// Test the connection pool
pool.getConnection()
  .then(connection => {
    console.log('Database connected successfully with connection pooling');
    connection.release(); // Release the connection back to the pool
  })
  .catch(err => {
    console.error('Error connecting to the database:', err.message);
    process.exit(1);
  });

// Graceful shutdown
process.on('SIGINT', async () => {
  try {
    await pool.end();
    console.log('Connection pool closed gracefully');
    process.exit(0);
  } catch (err) {
    console.error('Error closing connection pool:', err);
    process.exit(1);
  }
});

module.exports = pool;
```

## 2. **src/db/queries.js** - Update queries to use connection pool

```javascript
const pool = require('./connection');

class Queries {
  // Generic query method
  static async query(sql, params = []) {
    let connection;
    try {
      connection = await pool.getConnection();
      const [results] = await connection.execute(sql, params);
      return results;
    } catch (error) {
      console.error('Query error:', error.message);
      throw error;
    } finally {
      if (connection) connection.release();
    }
  }

  // User queries
  static async findUserById(id) {
    const sql = 'SELECT * FROM users WHERE id = ?';
    const results = await this.query(sql, [id]);
    return results[0];
  }

  static async findUserByEmail(email) {
    const sql = 'SELECT * FROM users WHERE email = ?';
    const results = await this.query(sql, [email]);
    return results[0];
  }

  static async createUser(userData) {
    const sql = 'INSERT INTO users (name, email, password) VALUES (?, ?, ?)';
    const params = [userData.name, userData.email, userData.password];
    const result = await this.query(sql, params);
    return { id: result.insertId, ...userData };
  }

  static async updateUser(id, userData) {
    const sql = 'UPDATE users SET name = ?, email = ? WHERE id = ?';
    const params = [userData.name, userData.email, id];
    await this.query(sql, params);
    return { id, ...userData };
  }

  static async deleteUser(id) {
    const sql = 'DELETE FROM users WHERE id = ?';
    await this.query(sql, [id]);
    return true;
  }

  static async getAllUsers(limit = 100, offset = 0) {
    const sql = 'SELECT * FROM users LIMIT ? OFFSET ?';
    return await this.query(sql, [limit, offset]);
  }

  // Transaction example
  static async executeTransaction(operations) {
    let connection;
    try {
      connection = await pool.getConnection();
      await connection.beginTransaction();

      // Execute operations
      for (const operation of operations) {
        await connection.execute(operation.sql, operation.params);
      }

      await connection.commit();
      return true;
    } catch (error) {
      if (connection) await connection.rollback();
      throw error;
    } finally {
      if (connection) connection.release();
    }
  }

  // Batch operations
  static async batchInsert(table, data) {
    if (!data.length) return [];

    const columns = Object.keys(data[0]);
    const placeholders = data.map(() => `(${columns.map(() => '?').join(',')})`).join(',');
    const values = data.flatMap(row => columns.map(col => row[col]));

    const sql = `INSERT INTO ${table} (${columns.join(',')}) VALUES ${placeholders}`;
    const result = await this.query(sql, values);
    return result;
  }
}

module.exports = Queries;
