## 4. **Optional: Create a middleware for database connections** (src/middleware/db.js)

```javascript
const pool = require('../db/connection');

const dbMiddleware = async (req, res, next) => {
  try {
    // Get a connection from the pool and attach it to the request
    req.dbConnection = await pool.getConnection();

    // Release the connection when response is finished
    res.on('finish', () => {
      if (req.dbConnection) {
        req.dbConnection.release();
      }
    });

    next();
  } catch (error) {
    console.error('Database connection error:', error);
    res.status(500).json({ error: 'Database connection failed' });
  }
};

module.exports = dbMiddleware;
```

## 5. **Update your main app file** (app.js or server.js)

```javascript
const express = require('express');
const dbMiddleware = require('./src/middleware/db'); // Optional middleware
const User = require('./src/models/user');

const app = express();

// Optional: Use middleware for database connections
app.use(dbMiddleware);

// Example route using the new User model
app.get('/users/:id', async (req, res) => {
  try {
    const user = await User.findById(req.params.id);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }
    res.json(user.toJSON());
  } catch (error) {
    console.error('Error fetching user:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

## Key Benefits of Connection Pooling:

1. **Performance**: Reuses connections instead of creating new ones for each query
2. **Scalability**: Handles multiple concurrent requests efficiently
3. **Resource Management**: Limits the number of simultaneous connections
4. **Connection Management**: Automatically handles connection timeouts and retries
5. **Graceful Shutdown**: Properly closes all connections on application exit

## Environment Variables (.env):

```env
