I'll help you add CORS configuration to your Express server. Here's how to do it:

## Step 1: Install CORS package
First, install the CORS package if you haven't already:

```bash
npm install cors
```

## Step 2: Configure CORS in `src/app.js`

Here's how to add CORS configuration to your Express server:

```javascript
// src/app.js
const express = require('express');
const cors = require('cors'); // Import CORS package

const app = express();

// Basic CORS configuration (allow all origins)
app.use(cors());

// OR for more specific configuration:
app.use(cors({
  origin: 'http://localhost:3000', // Allow only specific origin
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'], // Allowed methods
  allowedHeaders: ['Content-Type', 'Authorization'], // Allowed headers
  credentials: true, // Allow cookies/credentials
  optionsSuccessStatus: 200 // For legacy browser support
}));

// OR for multiple origins:
const allowedOrigins = ['http://localhost:3000', 'https://yourdomain.com'];
app.use(cors({
  origin: function (origin, callback) {
    // Allow requests with no origin (like mobile apps or curl requests)
    if (!origin) return callback(null, true);

    if (allowedOrigins.indexOf(origin) === -1) {
      const msg = 'The CORS policy for this site does not allow access from the specified origin.';
      return callback(new Error(msg), false);
    }
    return callback(null, true);
  },
  credentials: true
}));

// Your existing routes and middleware
app.use(express.json());
// ... rest of your code

module.exports = app;
```

## Step 3: Alternative - Configure CORS per route

If you need different CORS settings for different routes:

```javascript
// src/app.js
const express = require('express');
const cors = require('cors');

const app = express();

// Default CORS for all routes
app.use(cors());

// Specific CORS for a particular route
const specificCors = cors({
  origin: 'https://specific-domain.com',
  methods: ['GET', 'POST']
});

app.get('/api/sensitive-data', specificCors, (req, res) => {
  res.json({ message: 'This route has specific CORS settings' });
});

// ... rest of your code
```

## Recommended minimal configuration:

For most use cases, this configuration works well:

```javascript
// src/app.js
const express = require('express');
const cors = require('cors');

const app = express();

// Configure CORS
app.use(cors({
  origin: process.env.NODE_ENV === 'production' 
    ? 'https://your-production-domain.com' 
    : 'http://localhost:3000',
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization']
}));

// ... rest of your existing code
```

## Important Notes:

1. **Security**: In production, always specify exact origins instead of using `cors()` without options
2. **Environment Variables**: Consider using environment variables for origins
3. **Order**: CORS middleware should be added before your routes
4. **Preflight Requests**: The OPTIONS method is automatically handled by the CORS middleware

Choose the configuration that best fits your needs based on whether you're developing locally or deploying to production.

