  const fc = plan.file_changes || [];
  const ra = plan.risk_assessment || [];
  if (ra.length === 0) return { pass: false, score: 0, reason: 'No risk_assessment entries' };
  if (ra.length < fc.length)
    return { pass: false, score: 0, reason: `Only ${ra.length} risks for ${fc.length} file_changes` };
  return { pass: true, score: 1, reason: `${ra.length} risks for ${fc.length} changes` };
} catch (e) {
  return { pass: false, score: 0, reason: `Parse error: ${e.message}` };
}

const m = output.match(/\{[\s\S]*\}/);
if (!m) return { pass: false, score: 0, reason: 'No JSON found' };
try {
  const plan = JSON.parse(m[0]);
  const vs = plan.verification_steps || [];
  if (vs.length === 0) return { pass: false, score: 0, reason: 'No verification_steps' };
  const executable = vs.filter(s => s.command && s.command.trim().length > 10);
  if (executable.length === 0)
    return { pass: false, score: 0, reason: 'No steps with executable commands (>10 chars)' };
  const behavioral = executable.some(s =>
    s.command.includes('python') || s.command.includes('node') ||
    s.command.includes('curl') || s.command.includes('pytest') ||
    s.command.includes('bash'));
  if (!behavioral)
    return { pass: false, score: 0, reason: 'Commands are not behavioral tests (no python/node/curl/pytest)' };
  return { pass: true, score: 1, reason: `${executable.length} executable verification steps` };
} catch (e) {
  return { pass: false, score: 0, reason: `Parse error: ${e.message}` };
}

const m = output.match(/\{[\s\S]*\}/);
if (!m) return { pass: false, score: 0, reason: 'No JSON found' };
try {
  const plan = JSON.parse(m[0]);
  if (!plan.steps || !plan.tools_per_step)
    return { pass: false, score: 0, reason: 'Missing steps or tools_per_step' };
  if (plan.steps.length !== plan.tools_per_step.length)
    return { pass: false, score: 0, reason: `Mismatch: ${plan.steps.length} steps vs ${plan.tools_per_step.length} tools_per_step` };
  if (plan.steps.length < 2)
    return { pass: false, score: 0, reason: `Only ${plan.steps.length} step — task requires multiple steps` };
  return { pass: true, score: 1, reason: `${plan.steps.length} aligned steps` };
} catch (e) {
  return { pass: false, score: 0, reason: `Parse error: ${e.message}` };
}

const trimmed = output.trim();
// Check if the output starts with { (possibly after whitespace)
const startsWithJson = /^\s*\{/.test(trimmed);
// Check if there's significant non-JSON text before or after
const m = trimmed.match(/^([\s\S]*?)(\{[\s\S]*\})([\s\S]*?)$/);
if (!m) return { pass: false, score: 0, reason: 'No JSON object found' };
const before = m[1].trim();
const after = m[3].trim();
const extraText = before.length + after.length;
if (extraText > 50) {
  return { pass: false, score: 0, reason: `${extraText} chars of non-JSON text (before: "${before.slice(0,30)}...", after: "${after.slice(0,30)}...")` };
}
return { pass: true, score: 1, reason: startsWithJson ? 'Clean JSON output' : `Minor preamble (${before.length} chars)` };

const m = output.match(/\{[\s\S]*\}/);
if (!m) return { pass: false, score: 0, reason: 'No JSON found' };
try {
  const plan = JSON.parse(m[0]);
  const issues = [];
  if (!plan.codebase_analysis?.files_read?.length) issues.push('codebase_analysis.files_read');
  if (!plan.tool_calls_planned?.length) issues.push('tool_calls_planned');
  if (!plan.verification_steps?.length) issues.push('verification_steps');
  if (issues.length > 0)
    return { pass: false, score: 0, reason: `Still missing: ${issues.join(', ')}` };
  return { pass: true, score: 1, reason: 'All previously missing fields now present' };
} catch (e) {
  return { pass: false, score: 0, reason: `Parse error: ${e.message}` };
}
